import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';

const Navbar = () => {
  const location = useLocation();
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const navLinks = [
    { path: '/', label: 'Home', icon: '🏠' },
    { path: '/politicians', label: 'Politicians', icon: '👥' },
    { path: '/promises', label: 'Promises', icon: '📝' },
    { path: '/feedback', label: 'Feedback', icon: '💬' },
    { path: '/news', label: 'News', icon: '📰' },
    { path: '/notifications', label: 'Notifications', icon: '🔔' },
  ];

  const isActive = (path) => {
    if (path === '/' && location.pathname === '/') return true;
    if (path !== '/' && location.pathname.startsWith(path)) return true;
    return location.pathname === path;
  };

  return (
    <nav className="bg-gradient-to-r from-amber-700 via-orange-600 to-red-700 text-white shadow-2xl sticky top-0 z-50 backdrop-blur-sm bg-opacity-95">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16 lg:h-20">
          {/* Logo with Sri Lankan inspired design */}
          <Link 
            to="/" 
            className="flex items-center space-x-3 group"
          >
            <div className="relative">
              <div className="absolute inset-0 bg-yellow-400 rounded-full blur-md opacity-50 group-hover:opacity-75 transition-opacity"></div>
              <div className="relative text-3xl font-bold bg-gradient-to-r from-yellow-400 to-amber-300 bg-clip-text text-transparent">
                Janaya<span className="text-white">360</span>
              </div>
            </div>
            <div className="hidden sm:block h-8 w-px bg-gradient-to-b from-transparent via-yellow-400 to-transparent"></div>
            <div className="hidden sm:block text-xs font-light text-yellow-200">
              Sri Lanka's<br />Political Hub
            </div>
          </Link>

          {/* Desktop Navigation */}
          <div className="hidden lg:flex items-center space-x-1">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className={`
                  group relative px-4 py-2 rounded-lg text-sm font-medium transition-all duration-300
                  ${isActive(link.path)
                    ? 'text-yellow-300 bg-white/10 shadow-lg'
                    : 'text-white/90 hover:text-yellow-300 hover:bg-white/5'
                  }
                `}
              >
                <span className="relative z-10 flex items-center gap-2">
                  <span className="text-lg">{link.icon}</span>
                  {link.label}
                </span>
                {isActive(link.path) && (
                  <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-gradient-to-r from-yellow-400 to-amber-500 rounded-full"></div>
                )}
                {!isActive(link.path) && (
                  <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-gradient-to-r from-yellow-400 to-amber-500 scale-x-0 group-hover:scale-x-100 transition-transform duration-300"></div>
                )}
              </Link>
            ))}
          </div>

          {/* Auth Buttons - Desktop */}
          <div className="hidden lg:flex items-center space-x-4">
            <Link
              to="/login"
              className="px-5 py-2 text-sm font-medium text-white border-2 border-yellow-400/50 rounded-lg hover:border-yellow-400 hover:bg-white/10 transition-all duration-300 backdrop-blur-sm"
            >
              Sign In
            </Link>
            <Link
              to="/register"
              className="px-5 py-2 text-sm font-medium bg-gradient-to-r from-yellow-500 to-amber-500 text-amber-900 rounded-lg hover:from-yellow-400 hover:to-amber-400 hover:shadow-lg hover:shadow-yellow-500/30 transition-all duration-300 font-semibold"
            >
              Get Started
            </Link>
          </div>

          {/* Mobile Menu Button */}
          <button
            onClick={() => setIsMenuOpen(!isMenuOpen)}
            className="lg:hidden relative w-10 h-10 flex items-center justify-center rounded-lg bg-white/10 hover:bg-white/20 transition-all duration-300 backdrop-blur-sm"
            aria-expanded="false"
          >
            <span className="sr-only">Open main menu</span>
            <div className="relative w-6 h-5">
              <span className={`absolute h-0.5 w-6 bg-white transform transition-all duration-300 ${!isMenuOpen ? 'top-0' : 'top-2 rotate-45'}`}></span>
              <span className={`absolute h-0.5 w-6 bg-white top-2 transition-all duration-300 ${!isMenuOpen ? 'opacity-100' : 'opacity-0'}`}></span>
              <span className={`absolute h-0.5 w-6 bg-white transform transition-all duration-300 ${!isMenuOpen ? 'top-4' : 'top-2 -rotate-45'}`}></span>
            </div>
          </button>
        </div>

        {/* Mobile Menu */}
        <div className={`lg:hidden overflow-hidden transition-all duration-500 ${isMenuOpen ? 'max-h-96 opacity-100' : 'max-h-0 opacity-0'}`}>
          <div className="px-2 pt-2 pb-4 space-y-2">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                onClick={() => setIsMenuOpen(false)}
                className={`
                  flex items-center gap-3 px-4 py-3 rounded-lg text-base font-medium transition-all duration-300
                  ${isActive(link.path)
                    ? 'bg-gradient-to-r from-yellow-500/20 to-amber-500/20 text-yellow-300 border-l-4 border-yellow-500'
                    : 'text-white/90 hover:bg-white/10 hover:text-yellow-300'
                  }
                `}
              >
                <span className="text-xl">{link.icon}</span>
                {link.label}
              </Link>
            ))}
            
            {/* Mobile Auth Buttons */}
            <div className="pt-4 space-y-3">
              <Link
                to="/login"
                onClick={() => setIsMenuOpen(false)}
                className="block w-full text-center px-4 py-2.5 text-sm font-medium text-white border-2 border-yellow-400/50 rounded-lg hover:border-yellow-400 hover:bg-white/10 transition-all duration-300"
              >
                Sign In
              </Link>
              <Link
                to="/register"
                onClick={() => setIsMenuOpen(false)}
                className="block w-full text-center px-4 py-2.5 text-sm font-medium bg-gradient-to-r from-yellow-500 to-amber-500 text-amber-900 rounded-lg hover:from-yellow-400 hover:to-amber-400 transition-all duration-300 font-semibold"
              >
                Get Started
              </Link>
            </div>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
